# Combine and Write
try:
    if validated_df1 and validated_df2:
        combined_df = validated_df1.union(validated_df2)
    elif validated_df1:
        combined_df = validated_df1
    elif validated_df2:
        combined_df = validated_df2
    else:
        print("No validation issues found.")
        combined_df = None

    if combined_df:
        combined_df.createOrReplaceTempView("temp_view")
        gold_df = spark.sql("SELECT * FROM temp_view")

        (gold_df.write
         .option(Constants.SERVER, SynapseDedicatedServer)
         .option(Constants.TEMP_FOLDER, f"abfss://temp@{TempFolder}/{tablename}_staging")
         .mode("append")
         .synapsesql(f"{SynapseDedicatedDatabase}.dbo.{tablename}"))

        print("Data validation results successfully written to Synapse.")
except Exception as e:
    print(f"Failed to write to Synapse: {e}")
    raise
